import React from "react";
import BarraLateral from "./BarraLateral";
import { FaPlus, FaChartBar, FaCalendarAlt, FaExclamationTriangle } from "react-icons/fa";
import "./Dashboard.css";

function Dashboard({ usuario, onCerrarSesion }) {
  const fechaActual = new Date();
  const opcionesFecha = { 
    weekday: 'long',
    day: 'numeric', 
    month: 'long', 
    year: 'numeric' 
  };
  const fechaFormateada = fechaActual.toLocaleDateString('es-ES', opcionesFecha);

  // Generar días del calendario
  const generarDiasCalendario = () => {
    const dias = [];
    const primerDia = new Date(2025, 8, 1); // Septiembre 2025
    const ultimoDia = new Date(2025, 8, 30); // 30 de septiembre 2025
    
    // Días de la semana
    const diasSemana = ['DOM', 'LUN', 'MAR', 'MIE', 'JUE', 'VIE', 'SAB'];
    
    // Generar calendario
    for (let i = 0; i < 35; i++) {
      const fecha = new Date(primerDia);
      fecha.setDate(primerDia.getDate() + i - primerDia.getDay());
      
      if (fecha >= primerDia && fecha <= ultimoDia) {
        dias.push(fecha.getDate());
      } else {
        dias.push(null);
      }
    }
    
    return { diasSemana, dias };
  };

  const { diasSemana, dias } = generarDiasCalendario();

  return (
    <div className="dashboard-container">
      {/* Barra lateral */}
      <BarraLateral usuario={usuario} onCerrarSesion={onCerrarSesion} />
      
      {/* Contenido principal */}
      <div className="contenido-principal">
        {/* Header de bienvenida */}
        <div className="bienvenida-header">
          <h1>¡Bienvenida, {usuario?.nombre || "Andrea"}!</h1>
          <span className="fecha">{fechaFormateada}</span>
        </div>

        {/* Botones de acción rápida */}
        <div className="acciones-rapidas">
          <div className="accion-item nueva-venta">
            <FaPlus className="icono-accion" />
            <span>Nueva Venta</span>
          </div>
          <div className="accion-item nuevo-producto">
            <FaPlus className="icono-accion" />
            <span>Nuevo Producto</span>
          </div>
          <div className="accion-item reporte-rapido">
            <FaChartBar className="icono-accion" />
            <span>Reporte Rápido</span>
          </div>
        </div>

        {/* Grid principal - 2 columnas */}
        <div className="main-grid">
          {/* Columna izquierda - Productos más vendidos */}
          <div className="columna productos-vendidos-col">
            <div className="productos-vendidos-section">
              <h3>Productos más vendidos</h3>
              <div className="lista-productos-vendidos">
                <div className="producto-vendido-item">
                  <span className="nombre-producto">Coca Cola 2.25L</span>
                  <div className="stats-producto">
                    <span className="ventas-count">120 ventas</span>
                    <span className="tendencia positiva">↑ 12%</span>
                  </div>
                </div>
                <div className="producto-vendido-item">
                  <span className="nombre-producto">Quilmes 1L</span>
                  <div className="stats-producto">
                    <span className="ventas-count">40 ventas</span>
                    <span className="tendencia negativa">↓ 5%</span>
                  </div>
                </div>
                <div className="producto-vendido-item">
                  <span className="nombre-producto">Azúcar 1Kg</span>
                  <div className="stats-producto">
                    <span className="ventas-count">60 ventas</span>
                    <span className="tendencia positiva">↑ 8%</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Columna derecha - Productos por reponer */}
          <div className="columna productos-reponer-col">
            <div className="productos-reponer-section">
              <h3>Productos por reponer</h3>
              <div className="lista-productos-reponer">
                <div className="producto-reponer-item">
                  <FaExclamationTriangle className="icono-alerta" />
                  <span className="nombre-producto">Fanta 500ml</span>
                  <span className="stock-info">8 uds</span>
                </div>
                <div className="producto-reponer-item">
                  <FaExclamationTriangle className="icono-alerta" />
                  <span className="nombre-producto">Yerba Playadito</span>
                  <span className="stock-info">5 uds</span>
                </div>
                <div className="producto-reponer-item">
                  <FaExclamationTriangle className="icono-alerta" />
                  <span className="nombre-producto">Café Cabrales</span>
                  <span className="stock-info">10 uds</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Calendario */}
        <div className="calendario-section">
          <h3>SEPTIEMBRE 2025</h3>
          <div className="calendario-grid">
            <div className="dias-semana">
              {diasSemana.map(dia => (
                <div key={dia} className="dia-semana">{dia}</div>
              ))}
            </div>
            <div className="dias-mes">
              {dias.map((dia, index) => (
                <div key={index} className={`dia-mes ${dia === 1 ? 'dia-actual' : ''}`}>
                  {dia}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Gráfico de ventas semanales */}
        <div className="ventas-semana-section">
          <h3>VENTAS SEMANALES</h3>
          <div className="grafico-barras">
            {['LUN', 'MAR', 'MIE', 'JUE', 'VIE', 'SAB', 'DOM'].map((dia, index) => (
              <div key={dia} className="barra-dia">
                <div className="barra" style={{height: `${40 + (index * 12)}px`}}></div>
                <span className="etiqueta-dia">{dia}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
